const now = new Date();
const eightHoursAgo = new Date(now.getTime() - 8 * 60 * 60 * 1000);
const shiftNames = { 6: 'Dagdienst (06:00-14:00)', 14: 'Middagdienst (14:00-22:00)', 22: 'Nachtdienst (22:00-06:00)' };
const hour = now.getHours();
return [{
  json: {
    shift_name: shiftNames[hour] || `Ploeg ${hour}:00`,
    period_start: eightHoursAgo.toISOString(),
    period_end: now.toISOString(),
    report_id: `SHIFT-${now.toISOString().slice(0,16).replace(/[-:T]/g,'')}`
  }
}];

const data = $input.all();
const period = $('Bepaal Ploegperiode').item.json;

const byTopic = {};
for (const item of data) {
  const t = item.json.topic;
  if (!byTopic[t]) byTopic[t] = [];
  byTopic[t].push(Number(item.json.value));
}

const avg = arr => arr.length ? (arr.reduce((a,b)=>a+b,0)/arr.length).toFixed(2) : 'N/A';
const sum = arr => arr.length ? arr.reduce((a,b)=>a+b,0).toFixed(1) : 'N/A';
const last = arr => arr.length ? arr[arr.length-1].toFixed(0) : 'N/A';

const temps = byTopic['idp/plc01/temperature'] || [];
const powers = byTopic['idp/plc02/power_kw'] || [];
const rates = byTopic['idp/plc03/production_rate'] || [];
const counters = byTopic['idp/plc03/batch_counter'] || [];

const avgRate = Number(avg(rates));
const targetRate = 120;
const performance = targetRate > 0 ? Math.min(100, (avgRate / targetRate * 100)).toFixed(1) : 'N/A';
const produced = counters.length >= 2 ? (counters[counters.length-1] - counters[0]).toFixed(0) : last(counters);

return [{
  json: {
    report_id: period.report_id,
    shift: period.shift_name,
    period_start: period.period_start,
    period_end: period.period_end,
    kpis: {
      avg_temperature_c: avg(temps),
      avg_production_rate: avg(rates),
      performance_pct: performance,
      total_energy_kwh: (Number(avg(powers)) * 8).toFixed(1),
      units_produced: produced
    },
    generated_at: new Date().toISOString()
  }
}];
